import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Properly encoding user input before including it in the response
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedUserInput = codec.encodeForHTML(userInput);

        // Handling user input in the response with proper encoding
        String response = "<html><body>Welcome, " + encodedUserInput + "</body></html>";

        System.out.println(response);
    }
}

